const inputData = $input.first().json;
const webhookData = $node['Webhook Trigger'].json;

// Extract variables from the Webhook and API response
const vehicleValue = parseFloat(webhookData.body?.vehicleValue) || 0;
const loanPayoffAmount = parseFloat(webhookData.body?.loanPayoffAmount) || 0;
// Use API credit score if available, fallback to webhook value or default 700
const creditScore = inputData.creditScore || parseInt(webhookData.body?.creditScore) || 700;

// Calculate Equity
const equity = vehicleValue - loanPayoffAmount;

// Determine Finance Tier based on Credit Score
let financeTier = 'Subprime';
if (creditScore >= 720) {
  financeTier = 'Prime Plus';
} else if (creditScore >= 680) {
  financeTier = 'Prime';
} else if (creditScore >= 620) {
  financeTier = 'Near Prime';
}

return [{
  json: {
    status: 'success',
    equity: equity,
    equityStatus: equity >= 0 ? 'Positive' : 'Negative',
    creditScore: creditScore,
    financeTier: financeTier,
    vehicleValue: vehicleValue,
    loanPayoffAmount: loanPayoffAmount,
    calculatedAt: new Date().toISOString()
  }
}];
